import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { getLiveHealthAlerts, getLocalHealthAlerts } from '../services/geminiService';
import type { Alert, AlertCategory } from '../types';
import { BiohazardIcon, WindIcon, SunIcon, GlobeIcon, MegaphoneIcon, MapPinIcon, BellIcon } from './icons';
import { LoadingSpinner } from './LoadingSpinner';
import { AlertDetailModal } from './AlertDetailModal';

const ALERTS_ENABLED_KEY = 'geosick_alerts_enabled';

const getIconForCategory = (category: AlertCategory, className: string = "w-5 h-5") => {
    switch (category) {
        case 'disease': return <BiohazardIcon className={`${className} text-red-500`} />;
        case 'air': return <WindIcon className={`${className} text-slate-500`} />;
        case 'heat': return <SunIcon className={`${className} text-orange-500`} />;
        case 'environmental': return <GlobeIcon className={`${className} text-green-500`} />;
        case 'other': return <MegaphoneIcon className={`${className} text-purple-500`} />;
        default: return <GlobeIcon className={`${className} text-blue-500`} />;
    }
};

export const LiveHealthAlerts: React.FC = () => {
    const [isLiveEnabled, setIsLiveEnabled] = useState(() => {
        const stored = localStorage.getItem(ALERTS_ENABLED_KEY);
        return stored !== 'false'; // Default to true if not set
    });

    const [alerts, setAlerts] = useState<{ global: Alert[], local: Alert[] }>({ global: [], local: [] });
    const [currentAlertIndex, setCurrentAlertIndex] = useState(0);
    const [selectedAlert, setSelectedAlert] = useState<Alert | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const combinedAlerts = useMemo(() => {
        const local = alerts.local;
        const global = alerts.global;

        const uniqueGlobal = global.filter(g => 
            !local.some(l => l.title === g.title && l.location === g.location)
        );

        // Always prioritize local alerts at the beginning of the list
        return [...local, ...uniqueGlobal];
    }, [alerts]);

    const fetchAlerts = useCallback(async () => {
        if (!isLiveEnabled) return;

        setIsLoading(true);
        setError(null);

        const fetchGlobal = getLiveHealthAlerts().catch(e => {
            console.error("Failed to fetch global alerts:", e);
            setError(prev => prev ? `${prev} & failed to get global alerts.` : "Could not fetch global alerts.");
            return []; // Return empty array on error
        });

        const fetchLocal = new Promise<Alert[]>(resolve => {
            navigator.geolocation.getCurrentPosition(
                position => {
                    const { latitude, longitude } = position.coords;
                    getLocalHealthAlerts(latitude, longitude)
                        .then(resolve)
                        .catch(e => {
                            console.error("Failed to fetch local alerts:", e);
                            resolve([]);
                        });
                },
                () => {
                    console.warn("Geolocation failed. Local alerts not available.");
                    resolve([]); // Resolve with empty array if geolocation fails
                },
                { timeout: 5000 }
            );
        });

        const [globalAlerts, localAlerts] = await Promise.all([fetchGlobal, fetchLocal]);

        setAlerts({ global: globalAlerts, local: localAlerts });
        setIsLoading(false);
    }, [isLiveEnabled]);

    useEffect(() => {
        if (isLiveEnabled) {
            fetchAlerts();
        } else {
            // Optional: Clear alerts when disabled to avoid stale data
            setAlerts({ global: [], local: [] });
        }
    }, [fetchAlerts, isLiveEnabled]);

    useEffect(() => {
        if (isLiveEnabled && combinedAlerts.length > 1) {
            const interval = setInterval(() => {
                setCurrentAlertIndex(prev => (prev + 1) % combinedAlerts.length);
            }, 30000); // 30 seconds
            return () => clearInterval(interval);
        }
    }, [combinedAlerts, isLiveEnabled]);

    const toggleLive = () => {
        const newState = !isLiveEnabled;
        setIsLiveEnabled(newState);
        localStorage.setItem(ALERTS_ENABLED_KEY, String(newState));
    };

    const currentAlert = combinedAlerts[currentAlertIndex];

    const renderContent = () => {
        if (!isLiveEnabled) {
            return (
                <div className="flex flex-col items-center justify-center h-48 text-center bg-slate-50/50 rounded-lg p-6 border-2 border-dashed border-slate-200">
                    <BellIcon className="w-12 h-12 mb-3 text-slate-300" />
                    <p className="font-semibold text-slate-600">Updates Paused</p>
                    <p className="text-sm text-slate-500 mb-4 max-w-xs">
                        Real-time alerts are paused to save data and API usage.
                    </p>
                    <button 
                        onClick={toggleLive} 
                        className="text-sm bg-blue-500 hover:bg-blue-600 text-white font-semibold py-2 px-6 rounded-full transition-all shadow-sm hover:shadow-md"
                    >
                        Enable Live Alerts
                    </button>
                </div>
            );
        }

        if (isLoading) {
            return (
                <div className="flex flex-col items-center justify-center h-48 text-center text-slate-500">
                    <LoadingSpinner />
                    <p className="mt-3 font-medium">Fetching Latest Health Alerts...</p>
                </div>
            );
        }

        if (error && combinedAlerts.length === 0) {
            return (
                <div className="flex flex-col items-center justify-center h-48 text-center text-red-600 bg-red-50 rounded-lg p-4">
                    <p className="font-bold">Error</p>
                    <p>{error}</p>
                </div>
            );
        }

        if (!currentAlert) {
             return (
                <div className="flex flex-col items-center justify-center h-48 text-center text-slate-500">
                    <p className="font-semibold">No Health Alerts</p>
                    <p className="text-sm">No significant health alerts found at this time.</p>
                </div>
            );
        }

        return (
            <div key={currentAlert.id} className="animate-fade-in w-full">
                <button
                    onClick={() => setSelectedAlert(currentAlert)}
                    className="w-full text-left p-4 bg-slate-50/80 rounded-lg hover:bg-slate-100 transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-blue-400"
                >
                    <div className="flex items-start gap-4">
                        <div className="flex-shrink-0 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center mt-1">
                            {getIconForCategory(currentAlert.category, "w-6 h-6")}
                        </div>
                        <div className="flex-grow min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                                {currentAlert.source === 'local' && (
                                    <span className="text-xs font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded-full">Local</span>
                                )}
                                <p className="text-base text-slate-800 font-semibold truncate">{currentAlert.title}</p>
                            </div>
                            <div className="flex items-center gap-2 text-sm text-slate-500 mt-1">
                                <MapPinIcon className="w-4 h-4 flex-shrink-0" />
                                <span className="truncate">{currentAlert.location}</span>
                            </div>
                        </div>
                         <span className="text-xs font-bold text-blue-500 self-center hidden sm:block">View Details &rarr;</span>
                    </div>
                    <div className="w-full bg-slate-200 rounded-full h-1 mt-4 overflow-hidden">
                         <div className="bg-blue-500 h-1 rounded-full animate-[progress-bar_30s_linear_infinite]"></div>
                    </div>
                </button>
                 <style>{`
                    @keyframes progress-bar {
                        from { width: 0%; }
                        to { width: 100%; }
                    }
                `}</style>
            </div>
        );
    };

    return (
        <section className="w-full max-w-4xl mx-auto py-8 mb-8">
            <div className="relative flex flex-col items-center mb-6">
                <div className="flex items-center gap-3">
                    <h2 className="text-xl sm:text-2xl font-bold text-slate-700">Live Health Alerts</h2>
                    <button
                        onClick={toggleLive}
                        className={`text-[10px] uppercase tracking-wider font-bold px-3 py-1 rounded-full border transition-all duration-300 ${
                            isLiveEnabled
                                ? 'bg-green-100 text-green-700 border-green-200 hover:bg-green-200'
                                : 'bg-slate-100 text-slate-500 border-slate-300 hover:bg-slate-200'
                        }`}
                        title={isLiveEnabled ? "Click to pause alerts and save API calls" : "Click to enable live alerts"}
                    >
                        {isLiveEnabled ? 'Live: ON' : 'Live: OFF'}
                    </button>
                </div>
                <div className="h-0.5 w-16 bg-blue-500 mt-2"></div>
            </div>

            <div className="mt-6 bg-white border border-slate-200/80 rounded-lg shadow-sm p-4 min-h-[10rem] flex items-center justify-center transition-all duration-300">
                {renderContent()}
            </div>
            {selectedAlert && <AlertDetailModal alert={selectedAlert} onClose={() => setSelectedAlert(null)} />}
        </section>
    );
};

import React, { useState, useEffect } from 'react';
import { HomePage } from './components/HomePage';
import { WelcomePage } from './components/WelcomePage';
import { GlobePage } from './components/GlobePage';
import { AboutPage } from './components/AboutPage';
import { ContactPage } from './components/ContactPage';
import { ChatBot } from './components/ChatBot';
import { ImageAnalysisPage } from './components/ImageAnalysisPage';
import { CheckupPage } from './components/CheckupPage';
import { PrescriptionAnalysisPage } from './components/PrescriptionAnalysisPage';
import { IntroAnimation } from './components/IntroAnimation';
import { MentalHealthPage } from './components/MentalHealthPage';
import { SymptomCheckerPage } from './components/SymptomCheckerPage';
import { AuthPage } from './components/AuthPage';
import { ActivityHistoryPage } from './components/ActivityHistoryPage';
import type { User, ActivityLogItem, Page } from './types';
import { HealthForecast } from './components/HealthForecast';
import { AdminDashboardPage } from './components/AdminDashboardPage';
import { ProfilePage } from './components/ProfilePage';
import { Sidebar } from './components/Sidebar';
import { AlertsPage } from './components/AlertsPage';
import { WaterLogPage } from './components/WaterLogPage';
import { Bars3Icon, GlobeIcon } from './components/icons';
import { FeedbackModal } from './components/FeedbackModal';
import { I18nProvider } from './components/I18n';

const ACTIVITY_HISTORY_KEY = 'geosick_activity_history';
const GLOBAL_ACTIVITY_HISTORY_KEY = 'geosick_global_activity_history';
const USERS_KEY = 'geosick_users';
const SESSION_KEY = 'geosick_session_phone';

function AppContent() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [showIntro, setShowIntro] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [showAuth, setShowAuth] = useState(false);
  const [activityHistory, setActivityHistory] = useState<ActivityLogItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFeedbackModalOpen, setIsFeedbackModalOpen] = useState(false);

  useEffect(() => {
    // Ensure admin user exists on first load
    try {
        const allUsers: User[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const adminEmail = 'nookanikshithllpsdsnr@gmail.com';
        const adminExists = allUsers.some(u => u.email === adminEmail);

        if (!adminExists) {
            const adminUser: User = {
                name: 'Admin',
                phone: '0000000000',
                email: adminEmail,
                password: 'nooka@nikki123',
                date_of_birth: '2000-01-01',
                created_at: new Date().toISOString(),
                isAdmin: true,
            };
            allUsers.push(adminUser);
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));
            console.log("Admin user created.");
        }
    } catch (error) {
        console.error("Failed to create admin user:", error);
    }

    // Check for a logged-in user in localStorage
    const checkSession = () => {
        try {
            const loggedInUserPhone = localStorage.getItem(SESSION_KEY);
            if (loggedInUserPhone) {
                const allUsers: any[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
                const currentUser = allUsers.find(u => u.phone === loggedInUserPhone);
                if (currentUser) {
                    const { password, ...userDetails } = currentUser;
                    setUser(userDetails);
                    setCurrentPage('welcome');
                } else {
                    localStorage.removeItem(SESSION_KEY);
                }
            }
        } catch (error) {
            console.error("Session validation failed:", error);
            localStorage.removeItem(SESSION_KEY);
        }
    };
    checkSession();

    // Load personal activity history
    try {
      const storedHistory = localStorage.getItem(ACTIVITY_HISTORY_KEY);
      if (storedHistory) {
          setActivityHistory(JSON.parse(storedHistory));
      }
    } catch (error) {
        console.error("Could not load activity history from localStorage:", error);
        localStorage.removeItem(ACTIVITY_HISTORY_KEY);
    }
  }, []);

  const addGlobalActivityToHistory = (item: ActivityLogItem) => {
      try {
          const globalHistory: ActivityLogItem[] = JSON.parse(localStorage.getItem(GLOBAL_ACTIVITY_HISTORY_KEY) || '[]');
          const newGlobalHistory = [item, ...globalHistory];
          localStorage.setItem(GLOBAL_ACTIVITY_HISTORY_KEY, JSON.stringify(newGlobalHistory));
      } catch (error) {
           console.error("Could not save global activity to localStorage:", error);
      }
  };

  const addActivityToHistory = (item: Omit<ActivityLogItem, 'id' | 'timestamp' | 'userPhone'>) => {
      if (!user) return;
      const newActivity: ActivityLogItem = {
          ...item,
          id: new Date().toISOString() + Math.random(),
          timestamp: Date.now(),
          userPhone: user.phone,
      };

      setActivityHistory(prevHistory => {
          const newHistory = [newActivity, ...prevHistory];
          try {
            localStorage.setItem(ACTIVITY_HISTORY_KEY, JSON.stringify(newHistory));
          } catch (error) {
              console.error("Could not save activity history to localStorage:", error);
          }
          return newHistory;
      });

      addGlobalActivityToHistory(newActivity);
  };

  const handleUpdateUser = (updatedDetails: Partial<User>) => {
    if (!user) return false;

    try {
        const allUsers: any[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const userIndex = allUsers.findIndex(u => u.phone === user.phone);

        if (userIndex !== -1) {
            const updatedUser = { ...allUsers[userIndex], ...updatedDetails };
            allUsers[userIndex] = updatedUser;
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));

            const { password, ...userDetails } = updatedUser;
            setUser(userDetails);
            return true;
        }
        return false;
    } catch (error) {
        console.error("Failed to update user:", error);
        return false;
    }
  };


  const handleAuthSuccess = (authedUser: User) => {
    // Update last_login_at for the user who just logged in.
    let userWithTimestamp = { ...authedUser };
    try {
        const allUsers: User[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const userIndex = allUsers.findIndex(u => u.phone === authedUser.phone);

        if (userIndex !== -1) {
            const now = new Date().toISOString();
            allUsers[userIndex].last_login_at = now;
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));
            userWithTimestamp.last_login_at = now; // Ensure state has latest login time
        }
    } catch (error) {
        console.error("Failed to update last login time:", error);
    }

    const { password, ...userDetails } = userWithTimestamp;
    setUser(userDetails);
    setShowAuth(false);
    setCurrentPage('welcome');
    localStorage.setItem(SESSION_KEY, userWithTimestamp.phone);

    addGlobalActivityToHistory({
        id: new Date().toISOString(),
        timestamp: Date.now(),
        userPhone: userWithTimestamp.phone,
        type: 'login',
        title: 'User Logged In',
        data: { message: `User ${userWithTimestamp.name} (${userWithTimestamp.phone}) logged in.` },
    });
  };

  const handleLogout = () => {
      setUser(null);
      setCurrentPage('home');
      localStorage.removeItem(SESSION_KEY);
      setIsFeedbackModalOpen(false);
  };

  const handleNavigation = (page: Page) => {
      setCurrentPage(page);
  };

  const renderPublicPages = () => {
    switch (currentPage) {
        case 'about':
            return <AboutPage onBack={() => setCurrentPage('home')} />;
        case 'contact':
            return <ContactPage onBack={() => setCurrentPage('home')} />;
        case 'explore':
             return <GlobePage onBack={() => setCurrentPage('home')} />;
        case 'home':
        default:
            return <HomePage
                onLoginClick={() => setShowAuth(true)}
                onAboutClick={() => setCurrentPage('about')}
                onContactClick={() => setCurrentPage('contact')}
                onExploreClick={() => setCurrentPage('explore')}
            />;
    }
  }

  const renderAuthenticatedApp = () => {
    if (!user) return null;

    const renderPage = () => {
        const isAdmin = !!user.isAdmin;
        switch (currentPage) {
            case 'welcome':
            case 'home': // Redirect home to welcome if logged in
                return <WelcomePage
                    user={user}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
            case 'live-alerts':
                return <AlertsPage />;
            case 'image-analysis':
                return <ImageAnalysisPage
                    onBack={() => setCurrentPage('welcome')}
                    onScheduleCheckup={() => setCurrentPage('checkup')}
                    onAnalysisComplete={addActivityToHistory}
                />;
            case 'prescription-analysis':
                return <PrescriptionAnalysisPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'checkup':
                return <CheckupPage onBack={() => setCurrentPage('image-analysis')} />;
            case 'mental-health':
                return <MentalHealthPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'symptom-checker':
                return <SymptomCheckerPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={addActivityToHistory} />;
            case 'health-briefing': 
                 return <HealthForecast onBack={() => setCurrentPage('welcome')} />;
            case 'activity-history':
                 return <ActivityHistoryPage history={activityHistory} onBack={() => setCurrentPage('welcome')} />;
            case 'profile':
                return <ProfilePage user={user} onBack={() => setCurrentPage('welcome')} onUpdateUser={handleUpdateUser} />;
            case 'water-log':
                return <WaterLogPage onBack={() => setCurrentPage('welcome')} />;
            case 'admin-dashboard':
                return isAdmin ? <AdminDashboardPage onBack={() => setCurrentPage('welcome')} /> : <p>Access Denied. You do not have permission to view this page.</p>;
            case 'about':
                 return <AboutPage onBack={() => setCurrentPage('welcome')} />;
            case 'contact':
                return <ContactPage onBack={() => setCurrentPage('welcome')} />;
            case 'explore':
                return <GlobePage onBack={() => setCurrentPage('welcome')} />;
            default:
                return <WelcomePage
                    user={user}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
        }
    };

    return (
        <div className="flex h-screen bg-slate-100">
            <Sidebar 
                user={user} 
                currentPage={currentPage} 
                onNavigate={(page: Page) => {
                    handleNavigation(page);
                    setIsSidebarOpen(false);
                }} 
                onLogout={handleLogout}
                isOpen={isSidebarOpen}
                onClose={() => setIsSidebarOpen(false)}
                onOpenFeedbackModal={() => setIsFeedbackModalOpen(true)}
            />
             <div className="flex-1 flex flex-col">
                <header className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between shadow-sm relative z-20">
                    <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 p-1" aria-label="Open menu">
                        <Bars3Icon className="w-6 h-6" />
                    </button>
                    <div className="flex items-center gap-2">
                        <GlobeIcon className="w-7 h-7 text-blue-500" />
                        <h1 className="text-lg font-bold tracking-tight text-slate-800">GeoSick</h1>
                    </div>
                    <div className="w-7"></div>
                </header>
                <main className="flex-1 overflow-y-auto">
                    {renderPage()}
                </main>
            </div>
        </div>
    );
  };

  if (showIntro) {
    return <IntroAnimation onComplete={() => setShowIntro(false)} />;
  }

  return (
    <>
      {user ? renderAuthenticatedApp() : renderPublicPages()}
      {user && <ChatBot onNavigate={handleNavigation} />}
      {user && isFeedbackModalOpen && (
        <FeedbackModal 
            user={user}
            onClose={() => setIsFeedbackModalOpen(false)} 
        />
      )}
      {showAuth && (
        <AuthPage
          onClose={() => setShowAuth(false)}
          onAuthSuccess={handleAuthSuccess}
        />
      )}
    </>
  );
}

export default function App() {
    return (
        <I18nProvider>
            <AppContent />
        </I18nProvider>
    );
}

