import React, { useState, useEffect } from 'react';
import { HomePage } from './components/HomePage';
import { WelcomePage } from './components/WelcomePage';
import { GlobePage } from './components/GlobePage';
import { AboutPage } from './components/AboutPage';
import { ContactPage } from './components/ContactPage';
import { ChatBot } from './components/ChatBot';
import { ImageAnalysisPage } from './components/ImageAnalysisPage';
import { CheckupPage } from './components/CheckupPage';
import { PrescriptionAnalysisPage } from './components/PrescriptionAnalysisPage';
import { IntroAnimation } from './components/IntroAnimation';
import { MentalHealthPage } from './components/MentalHealthPage';
import { SymptomCheckerPage } from './components/SymptomCheckerPage';
import { AuthPage } from './components/AuthPage';
import { ActivityHistoryPage } from './components/ActivityHistoryPage';
import type { User, ActivityLogItem, Page } from './types';
import { HealthForecast } from './components/HealthForecast';
import { AdminDashboardPage } from './components/AdminDashboardPage';
import { ProfilePage } from './components/ProfilePage';
import { Sidebar } from './components/Sidebar';
import { AlertsPage } from './components/AlertsPage';
import { WaterLogPage } from './components/WaterLogPage';
import { Bars3Icon, GlobeIcon } from './components/icons';
import { FeedbackModal } from './components/FeedbackModal';
import { I18nProvider } from './components/I18n';
import { saveUserProfile, addActivity, subscribeToHistory } from './services/firebaseService';

const USERS_KEY = 'geosick_users';
const SESSION_KEY = 'geosick_session_phone';

function AppContent() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [showIntro, setShowIntro] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [showAuth, setShowAuth] = useState(false);
  const [activityHistory, setActivityHistory] = useState<ActivityLogItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFeedbackModalOpen, setIsFeedbackModalOpen] = useState(false);

  useEffect(() => {
    // Ensure admin user exists on first load (Local Auth)
    try {
        const allUsers: User[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const adminEmail = 'nookanikshithllpsdsnr@gmail.com';
        const adminExists = allUsers.some(u => u.email === adminEmail);

        if (!adminExists) {
            const adminUser: User = {
                name: 'Admin',
                phone: '0000000000',
                email: adminEmail,
                password: 'nooka@nikki123',
                date_of_birth: '2000-01-01',
                created_at: new Date().toISOString(),
                isAdmin: true,
            };
            allUsers.push(adminUser);
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));
            console.log("Admin user created.");
        }
    } catch (error) {
        console.error("Failed to create admin user:", error);
    }

    // Check for a logged-in user in localStorage
    const checkSession = () => {
        try {
            const loggedInUserPhone = localStorage.getItem(SESSION_KEY);
            if (loggedInUserPhone) {
                const allUsers: any[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
                const currentUser = allUsers.find(u => u.phone === loggedInUserPhone);
                if (currentUser) {
                    const { password, ...userDetails } = currentUser;
                    setUser(userDetails);
                    setCurrentPage('welcome');
                } else {
                    localStorage.removeItem(SESSION_KEY);
                }
            }
        } catch (error) {
            console.error("Session validation failed:", error);
            localStorage.removeItem(SESSION_KEY);
        }
    };
    checkSession();
  }, []);

  // Sync Activity History from Firebase
  useEffect(() => {
      if (user) {
          const unsubscribe = subscribeToHistory(user.phone, (items) => {
              setActivityHistory(items);
          });
          return () => unsubscribe();
      } else {
          setActivityHistory([]);
      }
  }, [user]);

  const handleAddActivity = async (item: Omit<ActivityLogItem, 'id' | 'timestamp' | 'userPhone'>) => {
      if (!user) return;

      const newActivity: ActivityLogItem = {
          ...item,
          id: '', // ID will be generated by Firestore
          timestamp: Date.now(),
          userPhone: user.phone,
      };

      await addActivity(newActivity);
  };

  const handleUpdateUser = (updatedDetails: Partial<User>) => {
    if (!user) return false;

    try {
        const allUsers: any[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const userIndex = allUsers.findIndex(u => u.phone === user.phone);

        if (userIndex !== -1) {
            const updatedUser = { ...allUsers[userIndex], ...updatedDetails };
            allUsers[userIndex] = updatedUser;
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));

            const { password, ...userDetails } = updatedUser;
            setUser(userDetails);
            // Sync update to Firebase
            saveUserProfile(userDetails);
            return true;
        }
        return false;
    } catch (error) {
        console.error("Failed to update user:", error);
        return false;
    }
  };


  const handleAuthSuccess = (authedUser: User) => {
    // Update last_login_at for the user who just logged in.
    let userWithTimestamp = { ...authedUser };
    try {
        const allUsers: User[] = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const userIndex = allUsers.findIndex(u => u.phone === authedUser.phone);

        if (userIndex !== -1) {
            const now = new Date().toISOString();
            allUsers[userIndex].last_login_at = now;
            localStorage.setItem(USERS_KEY, JSON.stringify(allUsers));
            userWithTimestamp.last_login_at = now;
        }
    } catch (error) {
        console.error("Failed to update last login time:", error);
    }

    const { password, ...userDetails } = userWithTimestamp;
    setUser(userDetails);
    setShowAuth(false);
    setCurrentPage('welcome');
    localStorage.setItem(SESSION_KEY, userWithTimestamp.phone);

    // Sync user to Firebase DB
    saveUserProfile(userDetails);

    // Log login activity to Firebase
    addActivity({
        id: '', // generated by DB
        timestamp: Date.now(),
        userPhone: userWithTimestamp.phone,
        type: 'login',
        title: 'User Logged In',
        data: { message: `User ${userWithTimestamp.name} (${userWithTimestamp.phone}) logged in.` },
    });
  };

  const handleLogout = () => {
      setUser(null);
      setCurrentPage('home');
      localStorage.removeItem(SESSION_KEY);
      setIsFeedbackModalOpen(false);
  };

  const handleNavigation = (page: Page) => {
      setCurrentPage(page);
  };

  const renderPublicPages = () => {
    switch (currentPage) {
        case 'about':
            return <AboutPage onBack={() => setCurrentPage('home')} />;
        case 'contact':
            return <ContactPage onBack={() => setCurrentPage('home')} />;
        case 'explore':
             return <GlobePage onBack={() => setCurrentPage('home')} />;
        case 'home':
        default:
            return <HomePage
                onLoginClick={() => setShowAuth(true)}
                onAboutClick={() => setCurrentPage('about')}
                onContactClick={() => setCurrentPage('contact')}
                onExploreClick={() => setCurrentPage('explore')}
            />;
    }
  }

  const renderAuthenticatedApp = () => {
    if (!user) return null;

    const renderPage = () => {
        const isAdmin = !!user.isAdmin;
        switch (currentPage) {
            case 'welcome':
            case 'home': // Redirect home to welcome if logged in
                return <WelcomePage
                    user={user}
                    activityHistory={activityHistory}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
            case 'live-alerts':
                return <AlertsPage />;
            case 'image-analysis':
                return <ImageAnalysisPage
                    onBack={() => setCurrentPage('welcome')}
                    onScheduleCheckup={() => setCurrentPage('checkup')}
                    onAnalysisComplete={handleAddActivity}
                />;
            case 'prescription-analysis':
                return <PrescriptionAnalysisPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'checkup':
                return <CheckupPage onBack={() => setCurrentPage('image-analysis')} />;
            case 'mental-health':
                return <MentalHealthPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'symptom-checker':
                return <SymptomCheckerPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'health-briefing': 
                 return <HealthForecast onBack={() => setCurrentPage('welcome')} />;
            case 'activity-history':
                 return <ActivityHistoryPage history={activityHistory} onBack={() => setCurrentPage('welcome')} />;
            case 'profile':
                return <ProfilePage user={user} onBack={() => setCurrentPage('welcome')} onUpdateUser={handleUpdateUser} />;
            case 'water-log':
                return <WaterLogPage onBack={() => setCurrentPage('welcome')} />;
            case 'admin-dashboard':
                return isAdmin ? <AdminDashboardPage onBack={() => setCurrentPage('welcome')} /> : <p>Access Denied. You do not have permission to view this page.</p>;
            case 'about':
                 return <AboutPage onBack={() => setCurrentPage('welcome')} />;
            case 'contact':
                return <ContactPage onBack={() => setCurrentPage('welcome')} />;
            case 'explore':
                return <GlobePage onBack={() => setCurrentPage('welcome')} user={user} />;
            default:
                return <WelcomePage
                    user={user}
                    activityHistory={activityHistory}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
        }
    };

    return (
        <div className="flex h-screen bg-slate-100">
            <Sidebar 
                user={user} 
                currentPage={currentPage} 
                onNavigate={(page: Page) => {
                    handleNavigation(page);
                    setIsSidebarOpen(false);
                }} 
                onLogout={handleLogout}
                isOpen={isSidebarOpen}
                onClose={() => setIsSidebarOpen(false)}
                onOpenFeedbackModal={() => setIsFeedbackModalOpen(true)}
            />
             <div className="flex-1 flex flex-col">
                <header className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between shadow-sm relative z-20">
                    <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 p-1" aria-label="Open menu">
                        <Bars3Icon className="w-6 h-6" />
                    </button>
                    <div className="flex items-center gap-2">
                        <GlobeIcon className="w-7 h-7 text-blue-500" />
                        <h1 className="text-lg font-bold tracking-tight text-slate-800">GeoSick</h1>
                    </div>
                    <div className="w-7"></div>
                </header>
                <main className="flex-1 overflow-y-auto">
                    {renderPage()}
                </main>
            </div>
        </div>
    );
  };

  if (showIntro) {
    return <IntroAnimation onComplete={() => setShowIntro(false)} />;
  }

  return (
    <>
      {user ? renderAuthenticatedApp() : renderPublicPages()}
      {user && <ChatBot onNavigate={handleNavigation} user={user} />}
      {user && isFeedbackModalOpen && (
        <FeedbackModal 
            user={user}
            onClose={() => setIsFeedbackModalOpen(false)} 
        />
      )}
      {showAuth && (
        <AuthPage
          onClose={() => setShowAuth(false)}
          onAuthSuccess={handleAuthSuccess}
        />
      )}
    </>
  );
}

export default function App() {
    return (
        <I18nProvider>
            <AppContent />
        </I18nProvider>
    );
}

import React, { useState, useEffect, useMemo } from 'react';
import type { User, WaterLogSettings, WaterLogEntry, HealthForecast as HealthForecastData, RiskFactor, ActivityLogItem } from '../types';
import { ScanIcon, StethoscopeIcon, DocumentChartBarIcon, SparklesIcon, ChevronRightIcon, SunIcon, WindIcon, HazardIcon, GlassWaterIcon } from './icons';
import { getHealthForecast } from '../services/geminiService';
import { HealthForecast } from './HealthForecast';
import { useI18n } from './I18n';

const WATER_LOG_SETTINGS_KEY = 'geosick_waterlog_settings';
const WATER_LOG_TODAY_KEY = 'geosick_waterlog_today';

const DEFAULT_SETTINGS: WaterLogSettings = {
  goal: 2500,
  notifications: { enabled: false, startTime: '09:00', endTime: '21:00', frequency: 60, },
};

const Card: React.FC<{ children: React.ReactNode; className?: string; style?: React.CSSProperties }> = ({ children, className = '', style }) => (
    <div 
        className={`bg-white/70 backdrop-blur-xl rounded-2xl shadow-md border border-white/40 transition-all duration-300 hover:shadow-xl hover:-translate-y-1 hover:border-white/60 ${className}`}
        style={style}
    >
        {children}
    </div>
);

const RiskFactorIcon: React.FC<{ name: string }> = ({ name }) => {
    const lowerCaseName = name.toLowerCase();
    if (lowerCaseName.includes('air quality')) return <WindIcon className="w-5 h-5 text-slate-500" />;
    if (lowerCaseName.includes('uv index')) return <SunIcon className="w-5 h-5 text-orange-400" />;
    if (lowerCaseName.includes('mosquito') || lowerCaseName.includes('pollen')) return <HazardIcon className="w-5 h-5 text-red-500" />;
    return <HazardIcon className="w-5 h-5 text-gray-500" />;
};

const HealthCastWidget: React.FC<{ onNavigate: () => void }> = ({ onNavigate }) => {
    const [forecast, setForecast] = useState<HealthForecastData | null>(null);
    const { language } = useI18n();

    useEffect(() => {
        navigator.geolocation.getCurrentPosition(
            async (position) => {
                try {
                    const { latitude, longitude } = position.coords;
                    const result = await getHealthForecast({ lat: latitude, lng: longitude }, language);
                    setForecast(result);
                } catch (err) { console.error(err); }
            },
            (err) => console.error(err),
            { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 }
        );
    }, [language]);

    const topRisks = useMemo(() => {
        if (!forecast) return [];
        const riskOrder = { 'Very High': 4, 'High': 3, 'Moderate': 2, 'Low': 1 };
        return [...forecast.riskFactors]
            .sort((a, b) => riskOrder[b.level] - riskOrder[a.level])
            .slice(0, 3);
    }, [forecast]);

    return (
        <div className="p-6">
            <h3 className="text-lg font-bold text-slate-800">Local Health Briefing</h3>
            <p className="text-sm text-slate-600 mb-4">{forecast?.locationName || 'Fetching your location...'}</p>
            {forecast ? (
                <>
                    <p className="text-sm text-slate-700 mb-4">{forecast.summary}</p>
                    <div className="space-y-3">
                        {topRisks.map(risk => (
                            <div key={risk.name} className="flex items-center gap-3">
                                <RiskFactorIcon name={risk.name} />
                                <div>
                                    <p className="text-sm font-semibold text-slate-800">{risk.name}</p>
                                    <p className="text-xs text-slate-500">{risk.level}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                    <button onClick={onNavigate} className="text-sm font-semibold text-blue-600 hover:text-blue-700 mt-4">
                        View Full Forecast &rarr;
                    </button>
                </>
            ) : <p className="text-sm text-slate-500">Loading local health data...</p>}
        </div>
    );
};

const WaterLogWidget: React.FC<{ onNavigate: () => void }> = ({ onNavigate }) => {
    const [settings, setSettings] = useState<WaterLogSettings>(DEFAULT_SETTINGS);
    const [log, setLog] = useState<WaterLogEntry[]>([]);

    useEffect(() => {
        try {
            const storedSettings = localStorage.getItem(WATER_LOG_SETTINGS_KEY);
            if (storedSettings) setSettings(JSON.parse(storedSettings));

            const storedLog = localStorage.getItem(WATER_LOG_TODAY_KEY);
            if (storedLog) {
                const todayLog = JSON.parse(storedLog);
                const today = new Date().toDateString();
                const filteredLog = todayLog.filter((entry: WaterLogEntry) => new Date(entry.timestamp).toDateString() === today);
                setLog(filteredLog);
            }
        } catch (e) { console.error("Failed to load water log data", e); }
    }, []);

    const totalIntake = useMemo(() => log.reduce((sum, entry) => sum + entry.amount, 0), [log]);
    const progress = useMemo(() => Math.min((totalIntake / settings.goal) * 100, 100), [totalIntake, settings.goal]);

    return (
        <div className="p-6">
            <h3 className="text-lg font-bold text-slate-800">Hydration Tracker</h3>
            <div className="flex items-center gap-4 mt-3">
                <div className="relative w-20 h-20">
                    <svg className="w-full h-full" viewBox="0 0 36 36">
                        <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="rgba(0, 0, 0, 0.1)" strokeWidth="3" />
                        <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="var(--accent-primary)" strokeWidth="3" strokeDasharray={`${progress}, 100`} strokeLinecap="round" transform="rotate(-90 18 18)" />
                    </svg>
                    <div className="absolute inset-0 flex flex-col items-center justify-center text-center">
                        <span className="text-xl font-bold text-slate-800">{Math.round(progress)}%</span>
                    </div>
                </div>
                <div>
                    <p className="text-lg font-semibold text-slate-800">{totalIntake} ml</p>
                    <p className="text-sm text-slate-600">Goal: {settings.goal} ml</p>
                </div>
            </div>
            <button onClick={onNavigate} className="text-sm font-semibold text-blue-600 hover:text-blue-700 mt-3">
                Log Water &rarr;
            </button>
        </div>
    );
};

const ActivityChart: React.FC<{ history: ActivityLogItem[] }> = ({ history }) => {
    const [data, setData] = useState<number[]>([]);
    const days = useMemo(() => ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'], []);

    useEffect(() => {
        try {
            const activityByDay = Array(7).fill(0);
            const today = new Date();
            today.setHours(0, 0, 0, 0);

            history.forEach(item => {
                const itemDate = new Date(item.timestamp);
                itemDate.setHours(0, 0, 0, 0);
                const diffDays = Math.floor((today.getTime() - itemDate.getTime()) / (1000 * 3600 * 24));
                if (diffDays >= 0 && diffDays < 7) {
                    const dayIndex = (today.getDay() - diffDays + 7) % 7;
                    activityByDay[dayIndex]++;
                }
            });

            // Reorder so today is the last day
            const dayOfWeek = today.getDay();
            const orderedData = [];
            for (let i = 0; i < 7; i++) {
                const index = (dayOfWeek + 1 + i) % 7;
                orderedData.push(activityByDay[index]);
            }
            setData(orderedData);
        } catch (e) {
            console.error("Failed to process activity data", e);
        }
    }, [history]);

    const maxActivity = Math.max(...data, 1); // Avoid division by zero

    return (
        <div className="p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                <DocumentChartBarIcon className="w-6 h-6 text-slate-600" />
                Your 7-Day Activity
            </h3>
            <div className="bar-chart-container">
                {data.map((value, index) => {
                    const dayIndex = (new Date().getDay() + 1 + index) % 7;
                    return (
                        <div key={index} className="bar-wrapper">
                            <div className="bar-tooltip">{value} analysis</div>
                            <div 
                                className="bar" 
                                style={{ height: `${(value / maxActivity) * 100}%` }}
                            ></div>
                            <span className="bar-label">{days[dayIndex]}</span>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

