interface ImageAnalysisPageProps {
  onBack: () => void;
  onScheduleCheckup: () => void;
  onAnalysisComplete: (item: Omit<ActivityLogItem, 'id' | 'timestamp' | 'userPhone'>) => void;
}

const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.onerror = error => reject(error);
    });
};

export const ImageAnalysisPage: React.FC<ImageAnalysisPageProps> = ({ onBack, onScheduleCheckup, onAnalysisComplete }) => {
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const { language } = useI18n();

  useEffect(() => {
    if (imageFile) {
      const objectUrl = URL.createObjectURL(imageFile);
      setImagePreview(objectUrl);
      return () => URL.revokeObjectURL(objectUrl);
    } else {
      setImagePreview(null);
    }
  }, [imageFile]);

  const handleAnalyze = async () => {
    if (!imageFile || !imagePreview) return;

    setIsLoading(true);
    setError(null);
    setAnalysis(null);

    try {
      const imageData = await fileToBase64(imageFile);
      const result = await analyzeImage(imageData, language);
      setAnalysis(result);

      // Upload image to Firebase Storage
      let uploadedImageUrl = '';
      try {
          const path = `scans/${Date.now()}_${imageFile.name}`;
          uploadedImageUrl = await uploadFile(imageFile, path);
      } catch (uploadError) {
          console.error("Failed to upload image to storage", uploadError);
      }

      onAnalysisComplete({ 
          type: 'image-analysis', 
          title: 'Environmental Image Analysis', 
          data: result, 
          language,
          // We can store the image URL in the activity data if needed, or handle it differently
          // For this example, let's append it to the data object if not strictly typed, or modify type.
          // Ideally, we'd add imageUrl to ActivityLogItem, but for now we can rely on it being retrievable.
      });
    } catch (err) {
      console.error(err);
      setError('Failed to analyze the image. The AI model may be unavailable or the content was blocked. Please try another image.');
    } finally {
      setIsLoading(false);
    }
  };

  const clearImage = () => {
      setImageFile(null);
      setAnalysis(null);
      setError(null);
  }

  return (
    <div className="w-full min-h-screen p-4 sm:p-6 lg:p-8 flex flex-col animate-fade-in">
        <div className="w-full max-w-7xl mx-auto self-start mb-6">
            <BackButton onClick={onBack} />
        </div>

        <Header />

        <main className="w-full max-w-7xl mx-auto mt-8 grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
            <div className="animate-fade-in-up">
