import { db, storage } from '../firebaseConfig';
import { collection, addDoc, query, where, orderBy, onSnapshot, setDoc, doc, getDoc, getDocs, limit } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import type { ActivityLogItem, User, ChatMessage } from '../types';

/**
 * Syncs user profile data to Firestore.
 */
export const saveUserProfile = async (user: User) => {
    try {
        console.log(`Attempting to sync profile for user: ${user.phone}`);
        const userRef = doc(db, 'users', user.phone);
        // We use setDoc with merge: true to update or create
        await setDoc(userRef, { ...user, last_login_at: new Date().toISOString() }, { merge: true });
        console.log("User profile successfully synced to Firestore.");
    } catch (e) {
        console.error("Error saving user profile:", e);
        throw e;
    }
};

/**
 * Gets a single user by phone number.
 */
export const getUserByPhone = async (phone: string): Promise<User | null> => {
    try {
        const docRef = doc(db, 'users', phone);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
            return docSnap.data() as User;
        }
        return null;
    } catch (e) {
        console.error("Error fetching user by phone:", e);
        throw e;
    }
};

/**
 * Gets a single user by email (for login via email).
 */
export const getUserByEmail = async (email: string): Promise<User | null> => {
    try {
        const q = query(collection(db, 'users'), where('email', '==', email), limit(1));
        const querySnapshot = await getDocs(q);
        if (!querySnapshot.empty) {
            return querySnapshot.docs[0].data() as User;
        }
        return null;
    } catch (e) {
        console.error("Error fetching user by email:", e);
        throw e;
    }
};

/**
 * Checks if a user exists and registers them if not.
 */
export const registerUser = async (user: User): Promise<void> => {
    // Check for existing phone
    const existingPhone = await getUserByPhone(user.phone);
    if (existingPhone) throw new Error("This phone number is already registered.");

    // Check for existing email if provided
    if (user.email) {
        const existingEmail = await getUserByEmail(user.email);
        if (existingEmail) throw new Error("This email address is already registered.");
    }

    await saveUserProfile(user);
};

/**
 * Uploads a file to Firebase Storage and returns the download URL.
 */
export const uploadFile = async (file: File, path: string): Promise<string> => {
    try {
        console.log(`Attempting to upload file to: ${path}`);
        const storageRef = ref(storage, path);
        const snapshot = await uploadBytes(storageRef, file);
        const url = await getDownloadURL(snapshot.ref);
        console.log("File uploaded successfully:", url);
        return url;
    } catch (e) {
        console.error("Error uploading file:", e);
        throw e;
    }
};

/**
 * Adds an activity log to Firestore.
 */
export const addActivity = async (activity: ActivityLogItem) => {
    try {
        console.log("Attempting to log activity:", activity.type);
        const { id, ...activityData } = activity;
        await addDoc(collection(db, 'activities'), activityData);
        console.log("Activity logged successfully to Firestore.");
    } catch (e) {
        console.error("Error adding activity:", e);
    }
};

/**
 * Subscribes to the user's activity history in real-time.
 */
export const subscribeToHistory = (userPhone: string, callback: (items: ActivityLogItem[]) => void) => {
    const q = query(
        collection(db, 'activities'),
        where('userPhone', '==', userPhone),
        orderBy('timestamp', 'desc')
    );

    return onSnapshot(q, (snapshot) => {
        const items = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ActivityLogItem));
        callback(items);
    }, (error) => {
        console.error("Error subscribing to history:", error);
    });
};

/**
 * Fetches all users for the Admin Dashboard.
 */
export const getAllUsers = async (): Promise<User[]> => {
    try {
        const querySnapshot = await getDocs(collection(db, 'users'));
        return querySnapshot.docs.map(doc => doc.data() as User);
    } catch (e) {
        console.error("Error fetching all users:", e);
        return [];
    }
};

/**
 * Fetches all activities for the Admin Dashboard.
 */
export const getAllActivities = async (): Promise<ActivityLogItem[]> => {
    try {
        const q = query(collection(db, 'activities'), orderBy('timestamp', 'desc'), limit(100));
        const querySnapshot = await getDocs(q);
        return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ActivityLogItem));
    } catch (e) {
        console.error("Error fetching all activities:", e);
        return [];
    }
};

/**
 * Saves a chat message to Firestore.
 */
export const saveChatMessage = async (userPhone: string, message: ChatMessage) => {
    try {
        await addDoc(collection(db, 'chats'), {
            userPhone,
            ...message,
            timestamp: Date.now()
        });
    } catch (e) {
        console.error("Error saving chat message:", e);
    }
};

/**
 * Saves a globe interaction (tap/search) to Firestore.
 */
export const saveGlobeInteraction = async (userPhone: string, interaction: any) => {
    try {
        await addDoc(collection(db, 'globe_interactions'), {
            userPhone,
            ...interaction,
            timestamp: Date.now()
        });
        console.log("Globe interaction saved.");
    } catch (e) {
        console.error("Error saving globe interaction:", e);
    }
};

import React, { useState } from 'react';
import { CloseIcon, GlobeIcon, PhoneIcon, LockClosedIcon, UserIcon, CalendarIcon, AtSymbolIcon } from './icons';
import RotatingGlobe from './RotatingGlobe';
import type { User } from '../types';
import { registerUser, getUserByPhone, getUserByEmail } from '../services/firebaseService';

interface AuthPageProps {
  onClose: () => void;
  onAuthSuccess: (user: User) => void;
}

type ViewMode = 'login' | 'signup';

export const AuthPage: React.FC<AuthPageProps> = ({ onClose, onAuthSuccess }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('login');

  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [dateOfBirth, setDateOfBirth] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loginIdentifier, setLoginIdentifier] = useState('');
  const [email, setEmail] = useState('');
  const [gender, setGender] = useState('');
  const [place, setPlace] = useState('');

  const [error, setError] = useState<string>('');
  const [infoMessage, setInfoMessage] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);

  const resetForms = () => {
    setPhone('');
    setPassword('');
    setError('');
    setName('');
    setDateOfBirth('');
    setConfirmPassword('');
    setInfoMessage('');
    setLoginIdentifier('');
    setEmail('');
    setGender('');
    setPlace('');
  }

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
        const identifier = loginIdentifier.trim();
        let foundUser: User | null = null;

        // Determine if input is email or phone (simple check: contains @)
        if (identifier.includes('@')) {
            foundUser = await getUserByEmail(identifier.toLowerCase());
        } else {
            foundUser = await getUserByPhone(identifier);
        }

        if (foundUser) {
            // Note: In a production app, verify password hash server-side or use Firebase Auth.
            // For this specific request to store credentials in DB profiles, we check the stored field.
            if (foundUser.password === password) {
                onAuthSuccess(foundUser);
            } else {
                throw new Error('Incorrect password. Please try again.');
            }
        } else {
            setInfoMessage("We couldn't find an account with this phone number or email. Please sign up to continue.");
            setViewMode('signup');
        }
    } catch (err: any) {
        console.error("Login error:", err);
        setError(err.message || "An unknown error occurred during login.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSignUp = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const adminEmail = 'nookanikshithllpsdsnr@gmail.com';
    if (email.trim().toLowerCase() === adminEmail) {
        setError('This email address is reserved and cannot be used for signup.');
        return;
    }

    if (password !== confirmPassword) {
        setError("Passwords do not match.");
        return;
    }
    if (!name.trim() || !phone.trim() || !dateOfBirth || !password) {
        setError("Please fill out all required fields: Full Name, Phone, Date of Birth, and Password.");
        return;
    }
    setIsLoading(true);

    try {
        const newUser: User = {
            phone: phone.trim(),
            name: name.trim(),
            email: email.trim() || null,
            date_of_birth: dateOfBirth,
            gender: gender || null,
            place: place.trim() || null,
            password: password,
            created_at: new Date().toISOString(),
        };

        await registerUser(newUser);
        onAuthSuccess(newUser);

    } catch (err: any) {
         console.error("Sign up error:", err);
         setError(err.message || "An unknown error occurred during sign up.");
    } finally {
         setIsLoading(false);
    }
  };

  const inputClasses = "w-full pl-11 pr-3 py-3 bg-white border border-slate-300 rounded-md placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-blue-500 focus:border-blue-500 transition-shadow";
