const formatDateTime = (dateString?: string | null) => {
    if (!dateString) return 'N/A';
    try {
        return new Date(dateString).toLocaleString(undefined, { dateStyle: 'short', timeStyle: 'short' });
    } catch {
        return dateString;
    }
};

