        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSave = async () => {
        // Optimistic UI update via the prop
        const success = onUpdateUser(formData);

        if (success) {
            try {
                // Async sync to Firebase
                await saveUserProfile({ ...user, ...formData });
                setIsEditing(false);
