const ChangePasswordModal: React.FC<{ user: User, onClose: () => void, onUpdateUser: (u: Partial<User>) => boolean }> = ({ user, onClose, onUpdateUser }) => {
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (newPassword !== confirmPassword) {
            setError("New passwords do not match.");
            return;
        }
        if (newPassword.length < 6) {
             setError("Password must be at least 6 characters long.");
            return;
        }

        setIsLoading(true);

        try {
            // Verify current password (using the local user object state for this demo/prototype)
            if (user.password !== currentPassword) {
                throw new Error("Your current password is not correct.");
            }

            // Update locally and attempt sync
            const updated = onUpdateUser({ password: newPassword });
            if (!updated) throw new Error("Failed to update password state.");

            // Sync to Firebase
            await saveUserProfile({ ...user, password: newPassword });

            setSuccess("Password changed successfully!");
            setCurrentPassword('');
            setNewPassword('');
            setConfirmPassword('');
            setTimeout(onClose, 1500);

        } catch (err: any) {
            setError(err.message || "An error occurred.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md animate-fade-in-up" onClick={e => e.stopPropagation()}>
                <header className="p-4 flex justify-between items-center border-b border-slate-200">
                     <h2 className="text-lg font-bold text-slate-800">Change Password</h2>
                     <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 flex-shrink-0">
                        <CloseIcon className="w-6 h-6 text-slate-600" />
                    </button>
                </header>
                <form onSubmit={handleSubmit} className="p-6 space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Current Password</label>
                        <input type="password" value={currentPassword} onChange={e => setCurrentPassword(e.target.value)} required className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-1 focus:ring-blue-500" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">New Password</label>
                        <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} required className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-1 focus:ring-blue-500" />
                    </div>
                     <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Confirm New Password</label>
                        <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-1 focus:ring-blue-500" />
                    </div>
                    {error && <p className="text-sm text-red-600">{error}</p>}
                    {success && <p className="text-sm text-green-600">{success}</p>}
                    <button type="submit" disabled={isLoading} className="w-full mt-2 bg-blue-500 hover:bg-blue-600 text-white font-semibold py-3 px-4 rounded-md transition-all duration-300 disabled:bg-slate-400">
                        {isLoading ? 'Saving...' : 'Update Password'}
                    </button>
                </form>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { HomePage } from './components/HomePage';
import { WelcomePage } from './components/WelcomePage';
import { GlobePage } from './components/GlobePage';
import { AboutPage } from './components/AboutPage';
import { ContactPage } from './components/ContactPage';
import { ChatBot } from './components/ChatBot';
import { ImageAnalysisPage } from './components/ImageAnalysisPage';
import { CheckupPage } from './components/CheckupPage';
import { PrescriptionAnalysisPage } from './components/PrescriptionAnalysisPage';
import { IntroAnimation } from './components/IntroAnimation';
import { MentalHealthPage } from './components/MentalHealthPage';
import { SymptomCheckerPage } from './components/SymptomCheckerPage';
import { AuthPage } from './components/AuthPage';
import { ActivityHistoryPage } from './components/ActivityHistoryPage';
import type { User, ActivityLogItem, Page } from './types';
import { HealthForecast } from './components/HealthForecast';
import { AdminDashboardPage } from './components/AdminDashboardPage';
import { ProfilePage } from './components/ProfilePage';
import { Sidebar } from './components/Sidebar';
import { AlertsPage } from './components/AlertsPage';
import { WaterLogPage } from './components/WaterLogPage';
import { Bars3Icon, GlobeIcon } from './components/icons';
import { FeedbackModal } from './components/FeedbackModal';
import { I18nProvider } from './components/I18n';
import { saveUserProfile, addActivity, subscribeToHistory, getUserByPhone } from './services/firebaseService';

const SESSION_KEY = 'geosick_session_phone';

function AppContent() {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [showIntro, setShowIntro] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [showAuth, setShowAuth] = useState(false);
  const [activityHistory, setActivityHistory] = useState<ActivityLogItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFeedbackModalOpen, setIsFeedbackModalOpen] = useState(false);

  // Initialize Admin User in Firestore
  useEffect(() => {
    const initAdmin = async () => {
        const adminPhone = '0000000000';
        try {
            const adminUser = await getUserByPhone(adminPhone);
            if (!adminUser) {
                const newAdmin: User = {
                    name: 'Admin',
                    phone: adminPhone,
                    email: 'nookanikshithllpsdsnr@gmail.com',
                    password: 'nooka@nikki123',
                    date_of_birth: '2000-01-01',
                    created_at: new Date().toISOString(),
                    isAdmin: true,
                };
                await saveUserProfile(newAdmin);
                console.log("Admin user initialized in Firestore.");
            }
        } catch (e) {
            console.error("Error checking/creating admin user:", e);
        }
    };
    initAdmin();
  }, []);

  // Check for existing session
  useEffect(() => {
    const checkSession = async () => {
        try {
            const loggedInUserPhone = localStorage.getItem(SESSION_KEY);
            if (loggedInUserPhone) {
                const currentUser = await getUserByPhone(loggedInUserPhone);
                if (currentUser) {
                    setUser(currentUser);
                    setCurrentPage('welcome');
                } else {
                    localStorage.removeItem(SESSION_KEY);
                }
            }
        } catch (error) {
            console.error("Session validation failed:", error);
            localStorage.removeItem(SESSION_KEY);
        }
    };
    checkSession();
  }, []);

  // Sync Activity History from Firebase
  useEffect(() => {
      if (user) {
          const unsubscribe = subscribeToHistory(user.phone, (items) => {
              setActivityHistory(items);
          });
          return () => unsubscribe();
      } else {
          setActivityHistory([]);
      }
  }, [user]);

  const handleAddActivity = async (item: Omit<ActivityLogItem, 'id' | 'timestamp' | 'userPhone'>) => {
      if (!user) return;

      const newActivity: ActivityLogItem = {
          ...item,
          id: '', // ID will be generated by Firestore
          timestamp: Date.now(),
          userPhone: user.phone,
      };

      await addActivity(newActivity);
  };

  const handleUpdateUser = (updatedDetails: Partial<User>) => {
    if (!user) return false;

    // Update local state immediately
    const updatedUser = { ...user, ...updatedDetails };
    setUser(updatedUser);

    // Note: The actual Firestore save is triggered within ProfilePage or can be done here.
    // ProfilePage currently handles the async save call.
    return true;
  };


  const handleAuthSuccess = (authedUser: User) => {
    const userWithTimestamp = { ...authedUser, last_login_at: new Date().toISOString() };

    setUser(userWithTimestamp);
    setShowAuth(false);
    setCurrentPage('welcome');
    localStorage.setItem(SESSION_KEY, userWithTimestamp.phone);

    // Sync login time to Firebase
    saveUserProfile(userWithTimestamp);

    // Log login activity to Firebase
    addActivity({
        id: '', // generated by DB
        timestamp: Date.now(),
        userPhone: userWithTimestamp.phone,
        type: 'login',
        title: 'User Logged In',
        data: { message: `User ${userWithTimestamp.name} (${userWithTimestamp.phone}) logged in.` },
    });
  };

  const handleLogout = () => {
      setUser(null);
      setCurrentPage('home');
      localStorage.removeItem(SESSION_KEY);
      setIsFeedbackModalOpen(false);
  };

  const handleNavigation = (page: Page) => {
      setCurrentPage(page);
  };

  const renderPublicPages = () => {
    switch (currentPage) {
        case 'about':
            return <AboutPage onBack={() => setCurrentPage('home')} />;
        case 'contact':
            return <ContactPage onBack={() => setCurrentPage('home')} />;
        case 'explore':
             return <GlobePage onBack={() => setCurrentPage('home')} />;
        case 'home':
        default:
            return <HomePage
                onLoginClick={() => setShowAuth(true)}
                onAboutClick={() => setCurrentPage('about')}
                onContactClick={() => setCurrentPage('contact')}
                onExploreClick={() => setCurrentPage('explore')}
            />;
    }
  }

  const renderAuthenticatedApp = () => {
    if (!user) return null;

    const renderPage = () => {
        const isAdmin = !!user.isAdmin;
        switch (currentPage) {
            case 'welcome':
            case 'home': // Redirect home to welcome if logged in
                return <WelcomePage
                    user={user}
                    activityHistory={activityHistory}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
            case 'live-alerts':
                return <AlertsPage />;
            case 'image-analysis':
                return <ImageAnalysisPage
                    onBack={() => setCurrentPage('welcome')}
                    onScheduleCheckup={() => setCurrentPage('checkup')}
                    onAnalysisComplete={handleAddActivity}
                />;
            case 'prescription-analysis':
                return <PrescriptionAnalysisPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'checkup':
                return <CheckupPage onBack={() => setCurrentPage('image-analysis')} />;
            case 'mental-health':
                return <MentalHealthPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'symptom-checker':
                return <SymptomCheckerPage onBack={() => setCurrentPage('welcome')} onAnalysisComplete={handleAddActivity} />;
            case 'health-briefing': 
                 return <HealthForecast onBack={() => setCurrentPage('welcome')} />;
            case 'activity-history':
                 return <ActivityHistoryPage history={activityHistory} onBack={() => setCurrentPage('welcome')} />;
            case 'profile':
                return <ProfilePage user={user} onBack={() => setCurrentPage('welcome')} onUpdateUser={handleUpdateUser} />;
            case 'water-log':
                return <WaterLogPage onBack={() => setCurrentPage('welcome')} />;
            case 'admin-dashboard':
                return isAdmin ? <AdminDashboardPage onBack={() => setCurrentPage('welcome')} /> : <p>Access Denied. You do not have permission to view this page.</p>;
            case 'about':
                 return <AboutPage onBack={() => setCurrentPage('welcome')} />;
            case 'contact':
                return <ContactPage onBack={() => setCurrentPage('welcome')} />;
            case 'explore':
                return <GlobePage onBack={() => setCurrentPage('welcome')} user={user} />;
            default:
                return <WelcomePage
                    user={user}
                    activityHistory={activityHistory}
                    onAnalyze={() => setCurrentPage('image-analysis')}
                    onAnalyzePrescription={() => setCurrentPage('prescription-analysis')}
                    onAnalyzeMentalHealth={() => setCurrentPage('mental-health')}
                    onCheckSymptoms={() => setCurrentPage('symptom-checker')}
                    onWaterLog={() => setCurrentPage('water-log')}
                />;
        }
    };

    return (
        <div className="flex h-screen bg-slate-100">
            <Sidebar 
                user={user} 
                currentPage={currentPage} 
                onNavigate={(page: Page) => {
                    handleNavigation(page);
                    setIsSidebarOpen(false);
                }} 
                onLogout={handleLogout}
                isOpen={isSidebarOpen}
                onClose={() => setIsSidebarOpen(false)}
                onOpenFeedbackModal={() => setIsFeedbackModalOpen(true)}
            />
             <div className="flex-1 flex flex-col">
                <header className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between shadow-sm relative z-20">
                    <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 p-1" aria-label="Open menu">
                        <Bars3Icon className="w-6 h-6" />
                    </button>
                    <div className="flex items-center gap-2">
                        <GlobeIcon className="w-7 h-7 text-blue-500" />
                        <h1 className="text-lg font-bold tracking-tight text-slate-800">GeoSick</h1>
                    </div>
                    <div className="w-7"></div>
                </header>
                <main className="flex-1 overflow-y-auto">
                    {renderPage()}
                </main>
            </div>
        </div>
    );
  };

  if (showIntro) {
    return <IntroAnimation onComplete={() => setShowIntro(false)} />;
  }

  return (
    <>
      {user ? renderAuthenticatedApp() : renderPublicPages()}
      {user && <ChatBot onNavigate={handleNavigation} user={user} />}
      {user && isFeedbackModalOpen && (
        <FeedbackModal 
            user={user}
            onClose={() => setIsFeedbackModalOpen(false)} 
        />
      )}
      {showAuth && (
        <AuthPage
          onClose={() => setShowAuth(false)}
          onAuthSuccess={handleAuthSuccess}
        />
      )}
    </>
  );
}

export default function App() {
    return (
        <I18nProvider>
            <AppContent />
        </I18nProvider>
    );
}

import React, { createContext, useContext, useState, useCallback } from 'react';
import { translations } from '../data/translations';

interface I18nContextType {
  language: string;
  setLanguage: (lang: string) => void;
  t: (key: string, replacements?: Record<string, string>) => string;
}

const I18nContext = createContext<I18nContextType>({
  language: 'en-US',
  setLanguage: () => {},
  t: (key) => key,
});

export const I18nProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguageState] = useState(() => {
    return localStorage.getItem('geosick_language') || 'en-US';
  });

  const setLanguage = (lang: string) => {
    localStorage.setItem('geosick_language', lang);
    setLanguageState(lang);
  };

  const t = useCallback((key: string, replacements?: Record<string, string>): string => {
    let translation = translations[key]?.[language] || translations[key]?.['en-US'] || key;
    if (replacements) {
        Object.keys(replacements).forEach(rKey => {
            translation = translation.replace(`{${rKey}}`, replacements[rKey]);
        });
    }
    return translation;
  }, [language]);

  return (
    <I18nContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </I18nContext.Provider>
  );
};

export const useI18n = () => useContext(I18nContext);

import { db, storage } from '../firebaseConfig';
import { collection, addDoc, query, where, orderBy, onSnapshot, setDoc, doc, getDoc, getDocs, limit } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import type { ActivityLogItem, User, ChatMessage } from '../types';

/**
 * Syncs user profile data to Firestore.
 */
export const saveUserProfile = async (user: User) => {
    try {
        console.log(`Attempting to sync profile for user: ${user.phone}`);
        const userRef = doc(db, 'users', user.phone);
        // We use setDoc with merge: true to update or create
        await setDoc(userRef, { ...user, last_login_at: new Date().toISOString() }, { merge: true });
        console.log("User profile successfully synced to Firestore.");
    } catch (e) {
        console.error("Error saving user profile:", e);
        throw e;
    }
};

/**
 * Gets a single user by phone number.
 */
export const getUserByPhone = async (phone: string): Promise<User | null> => {
    try {
        const docRef = doc(db, 'users', phone);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
            return docSnap.data() as User;
        }
        return null;
    } catch (e) {
        console.error("Error fetching user by phone:", e);
        throw e;
    }
};

/**
 * Gets a single user by email (for login via email).
 */
export const getUserByEmail = async (email: string): Promise<User | null> => {
    try {
        const q = query(collection(db, 'users'), where('email', '==', email), limit(1));
        const querySnapshot = await getDocs(q);
        if (!querySnapshot.empty) {
            return querySnapshot.docs[0].data() as User;
        }
        return null;
    } catch (e) {
        console.error("Error fetching user by email:", e);
        throw e;
    }
};

/**
 * Checks if a user exists and registers them if not.
 */
export const registerUser = async (user: User): Promise<void> => {
    // Check for existing phone
    const existingPhone = await getUserByPhone(user.phone);
    if (existingPhone) throw new Error("This phone number is already registered.");

    // Check for existing email if provided
    if (user.email) {
        const existingEmail = await getUserByEmail(user.email);
        if (existingEmail) throw new Error("This email address is already registered.");
    }

    await saveUserProfile(user);
};

/**
 * Uploads a file to Firebase Storage and returns the download URL.
 */
export const uploadFile = async (file: File, path: string): Promise<string> => {
    try {
        console.log(`Attempting to upload file to: ${path}`);
        const storageRef = ref(storage, path);
        const snapshot = await uploadBytes(storageRef, file);
        const url = await getDownloadURL(snapshot.ref);
        console.log("File uploaded successfully:", url);
        return url;
    } catch (e) {
        console.error("Error uploading file:", e);
        throw e;
    }
};

/**
 * Adds an activity log to Firestore.
 */
export const addActivity = async (activity: ActivityLogItem) => {
    try {
        console.log("Attempting to log activity:", activity.type);
        const { id, ...activityData } = activity;
        await addDoc(collection(db, 'activities'), activityData);
        console.log("Activity logged successfully to Firestore.");
    } catch (e) {
        console.error("Error adding activity:", e);
    }
};

/**
 * Subscribes to the user's activity history in real-time.
 * NOTE: Sorting is done client-side to avoid needing a composite index on (userPhone, timestamp).
 */
export const subscribeToHistory = (userPhone: string, callback: (items: ActivityLogItem[]) => void) => {
    const q = query(
        collection(db, 'activities'),
        where('userPhone', '==', userPhone)
    );

    return onSnapshot(q, (snapshot) => {
        const items = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as ActivityLogItem));
        // Client-side sort by timestamp descending
        items.sort((a, b) => b.timestamp - a.timestamp);
        callback(items);
    }, (error) => {
        console.error("Error subscribing to history:", error);
    });
};

