// Safer initialization function to avoid top-level crashes
const getAIClient = () => {
    // Check global process first (polyfill), then try standard access
    const apiKey = (typeof process !== 'undefined' && process.env && process.env.API_KEY) 
        ? process.env.API_KEY 
        : undefined;

    if (!apiKey) {
        console.error("API_KEY environment variable not set. API calls will fail.");
        // We throw here only when the client is requested, not at module load time.
        // This allows the app to render the initial UI even if configuration is missing.
        throw new Error("API_KEY environment variable not set");
    }
    return new GoogleGenAI({ apiKey });
};

// Helper function to introduce a delay
const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * A wrapper function for Gemini API calls that implements a retry mechanism
 * with exponential backoff for rate-limiting errors (429).
 */
async function callGeminiWithRetry<T>(
    apiCall: () => Promise<T>,
    maxRetries: number = 3,
    initialDelay: number = 1000
): Promise<T> {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            return await apiCall();
        } catch (error: any) {
            const isRateLimitError = error.toString().includes('429') || error.toString().includes('RESOURCE_EXHAUSTED');

            if (isRateLimitError && attempt < maxRetries - 1) {
                const delay = initialDelay * Math.pow(2, attempt);
                console.warn(`Rate limit hit. Retrying in ${delay}ms... (Attempt ${attempt + 1}/${maxRetries})`);
                await sleep(delay);
                attempt++;
            } else {
                console.error("API call failed after multiple retries or with a non-retriable error.", error);
                throw error;
            }
        }
    }
    throw new Error('Exceeded maximum retries for Gemini API call.');
}


