export const findFacilitiesByCoordinates = async (coords: { lat: number; lng: number }): Promise<Omit<Facility, 'distance'>[]> => {
    const cacheKey = `facilities_grounded_${coords.lat.toFixed(3)}_${coords.lng.toFixed(3)}`;
    const cached = cache.get<Omit<Facility, 'distance'>[]>(cacheKey);
    if (cached) {
        return cached;
    }

    // Step 1: Use Google Maps Grounding to get real data
    const groundingResponse = await callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Find 5-10 real medical facilities (Hospitals, Clinics, Pharmacies) near latitude ${coords.lat}, longitude ${coords.lng}. Return their names and addresses.`,
        config: {
            tools: [{ googleMaps: {} }],
        }
    }));

    // Step 2: Structure the data into JSON
    const structuringResponse = await callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Extract the facilities from the text below into a JSON array.
        For each facility, provide:
        - name: The name of the facility.
        - type: One of 'Hospital', 'Clinic', 'Pharmacy'.
        - lat: The latitude.
        - lng: The longitude.

        If exact coordinates are missing in the text, estimate them based on the provided address or proximity to ${coords.lat}, ${coords.lng}.

        Text: ${groundingResponse.text}`,
        config: {
            responseMimeType: "application/json",
            responseSchema: facilitiesSchema,
        }
    }));

    try {
        const jsonText = structuringResponse.text.trim();
        const result = JSON.parse(jsonText) as Omit<Facility, 'distance'>[];

        // Filter out obviously bad coordinates (0,0) if any
        const validResults = result.filter(f => f.lat !== 0 && f.lng !== 0);

        if (validResults.length > 0) {
             cache.set(cacheKey, validResults, 60); // Cache for 1 hour
             return validResults;
        } else {
             return [];
        }
    } catch (e) {
        console.error("Failed to parse facilities response:", structuringResponse.text);
        // Fallback: Return empty array rather than crashing
        return [];
    }
};

