    } catch (err) {
      console.error(err);
      setError('Failed to analyze the location. The AI model may be unavailable or the request was blocked. Please try another location.');
    } finally {
      setIsLoading(false);
    }
  }, [isLoading, language]);

  const startCityAnalysis = useCallback(async (city: City) => {
    if (isLoading) return;

