export const analyzeLocationByCoordinates = async (lat: number, lng: number, language: string, knownLocationName?: string): Promise<{ analysis: LocationAnalysisResult, imageUrl: string | null }> => {
    const cacheKey = `loc_v2_${lat.toFixed(4)}_${lng.toFixed(4)}_${language}`;
    const cached = cache.get<{ analysis: LocationAnalysisResult, imageUrl: string | null }>(cacheKey);
    if (cached) return cached;

    const contents = `Analyze coordinates ${lat}, ${lng}. Location: ${knownLocationName || 'Unknown'}. 
    Identify environmental health hazards based on local geography (e.g. wetlands for malaria, urban heat islands, industrial zones). 
    Provide associated diseases and precautions in ${language}. Return JSON.`;

    const [analysisResult, imageResult] = await Promise.allSettled([
        callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: contents,
            config: { responseMimeType: "application/json", responseSchema: locationAnalysisSchema }
        })),
        callGeminiWithRetry<GenerateImagesResponse>(() => ai.models.generateImages({
            model: 'imagen-4.0-generate-001',
            prompt: `Satellite view photo of latitude ${lat}, longitude ${lng}. Realistic biome terrain. No UI.`,
            config: { numberOfImages: 1, outputMimeType: 'image/jpeg', aspectRatio: '16:9' }
        }))
    ]);

    if (analysisResult.status === 'rejected') throw new Error("Analysis failed");

    let analysis = JSON.parse(analysisResult.value.text);
    let imageUrl: string | null = null;
    if (imageResult.status === 'fulfilled' && imageResult.value.generatedImages?.length) {
        imageUrl = `data:image/jpeg;base64,${imageResult.value.generatedImages[0].image.imageBytes}`;
    }

    const result = { analysis, imageUrl };
    cache.set(cacheKey, result, 30);
    return result;
};

export const analyzeImage = async (base64ImageData: string, language: string): Promise<AnalysisResult> => {
    const prompt = `You are a Forensic Environmental Epidemiologist. Analyze this image with extreme scrutiny. 
    1. Identify ANY environmental hazards: stagnant water, industrial waste, visible mold, poor sanitation, overcrowding, dust/pollution haze, or hazardous construction.
    2. Even if it is an indoor portrait, look for subtle cues: signs of damp walls, poor lighting affecting circadian health, presence of pests (cockroaches/rodents), or indicators of poor air quality.
    3. Map these hazards to specific diseases (e.g., Dengue, Respiratory Infections, Skin Allergies, Water-borne pathogens).
    4. Provide actionable community-level and individual precautions.
    The report must be comprehensive, clinical yet accessible. Language: ${language}. Return JSON.`;

    const response = await callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: base64ImageData } }, { text: prompt }] },
        config: { responseMimeType: "application/json", responseSchema: locationAnalysisSchema }
    }));

    return JSON.parse(response.text);
};

