export const findFacilitiesByCoordinates = async (coords: { lat: number; lng: number }): Promise<Omit<Facility, 'distance'>[]> => {
    const cacheKey = `hospitals_v3_${coords.lat.toFixed(4)}_${coords.lng.toFixed(4)}`;
    const cached = cache.get<Omit<Facility, 'distance'>[]>(cacheKey);
    if (cached) return cached;

    // Pass 1: Search for real-world places using Google Maps Grounding
    const searchResponse = await callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `List the names and addresses of the 10 closest hospitals, clinics, and pharmacies to GPS coordinates ${coords.lat}, ${coords.lng}. Use Google Maps search.`,
        config: { tools: [{ googleMaps: {} }] }
    }));

    // Pass 2: Extract pin-point accurate GPS coordinates for those specific results
    const structureResponse = await callGeminiWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Based on the following medical facilities found: "${searchResponse.text}", extract them into a JSON array. 
        CRITICAL: For each facility, search Google Maps to find their EXACT Latitude and Longitude. Mapping accuracy must be pin-point.`,
        config: { 
            tools: [{ googleMaps: {} }],
            responseMimeType: "application/json", 
            responseSchema: facilitiesSchema 
        }
    }));

    try {
        const results = JSON.parse(structureResponse.text);
        cache.set(cacheKey, results, 60);
        return results;
    } catch {
        return [];
    }
};

